import React, { useState, useEffect, useRef } from 'react';
import { useNavigate } from 'react-router-dom';
import { FaMapMarkedAlt, FaGlobeAsia, FaBook, FaChartLine, FaArrowRight, FaPlane, FaRoute, FaCalendarAlt, FaCheckCircle, FaMountain, FaPassport, FaSuitcaseRolling, FaCamera, FaMapPin } from 'react-icons/fa';
import './LandingPage.css';

const features = [
  { icon: <FaMapMarkedAlt />, title: 'India Map Dashboard', desc: 'Interactive map to track every state and union territory. Click, explore, conquer.' },
  { icon: <FaGlobeAsia />, title: 'World Map Explorer', desc: 'Pin countries across the globe with visit dates, notes, and flag emojis.' },
  { icon: <FaBook />, title: 'Destination Journal', desc: 'Log destinations within each state. Mark top spots. Track your exploration.' },
  { icon: <FaChartLine />, title: 'Travel Analytics', desc: 'Donut charts, progress rings, and stats that celebrate every journey.' },
  { icon: <FaCalendarAlt />, title: 'Trip Planner', desc: 'Plan upcoming adventures with dates, destinations, and personal notes.' },
  { icon: <FaCheckCircle />, title: 'Milestone Badges', desc: 'Unlock achievements as you explore. From First Step to All India.' },
];

const testimonials = [
  { text: 'Finally a beautiful way to see how much of India I have covered. Love the milestones!', name: 'Priya M.', role: 'Solo Traveler' },
  { text: 'The world map with flight arcs is stunning. I share my stats with friends all the time.', name: 'Arjun K.', role: 'Backpacker' },
  { text: 'Planning trips and tracking them in one place. This is exactly what I needed.', name: 'Sneha R.', role: 'Travel Blogger' },
];

export default function LandingPage() {
  const navigate = useNavigate();
  const [scrollY, setScrollY] = useState(0);
  const mapRef = useRef(null);

  useEffect(() => {
    const token = localStorage.getItem('token');
    if (token) navigate('/dashboard');
  }, [navigate]);

  useEffect(() => {
    if (!mapRef.current) return;
    fetch('/WorldMap_SVG_Source.normalized.svg')
      .then(res => res.text())
      .then(svgContent => {
        if (!mapRef.current) return;
        mapRef.current.innerHTML = svgContent;
        const svg = mapRef.current.querySelector('svg');
        if (!svg) return;
        const W = 2754, H = 1398;
        svg.setAttribute('viewBox', `0 0 ${W} ${H}`);
        svg.removeAttribute('width');
        svg.removeAttribute('height');
        svg.style.width = '100%';
        svg.style.height = '100%';
        svg.style.display = 'block';
        svg.setAttribute('preserveAspectRatio', 'xMidYMid meet');
        const styleEl = svg.querySelector('style');
        if (styleEl) styleEl.remove();
        svg.querySelectorAll('circle').forEach(c => c.setAttribute('opacity', '0'));
        svg.querySelectorAll('path').forEach(path => {
          path.setAttribute('fill', '#2a4a6b');
          path.setAttribute('stroke', '#1a3352');
          path.setAttribute('stroke-width', '0.5');
        });
        const visited = ['India', 'France', 'Australia', 'Brazil', 'Japan'];
        svg.querySelectorAll('g').forEach(g => {
          const title = g.querySelector('title');
          if (title && visited.some(v => title.textContent.includes(v))) {
            g.querySelectorAll('path').forEach(p => {
              p.setAttribute('fill', '#34d399');
              p.setAttribute('stroke', '#6ee7b7');
              p.setAttribute('stroke-width', '0.8');
            });
          }
        });
        // Flight arcs
        const ns = 'http://www.w3.org/2000/svg';
        const overlay = document.createElementNS(ns, 'g');
        const routes = [
          { x1: 0.53, y1: 0.30, x2: 0.72, y2: 0.40, color: '#60a5fa' },
          { x1: 0.72, y1: 0.40, x2: 0.87, y2: 0.33, color: '#a78bfa' },
          { x1: 0.17, y1: 0.32, x2: 0.53, y2: 0.30, color: '#22d3ee' },
          { x1: 0.72, y1: 0.40, x2: 0.84, y2: 0.72, color: '#fbbf24' },
        ];
        routes.forEach((r, i) => {
          const x1 = r.x1*W, y1 = r.y1*H, x2 = r.x2*W, y2 = r.y2*H;
          const mx = (x1+x2)/2, my = Math.min(y1,y2) - Math.abs(x2-x1)*0.18;
          const arc = document.createElementNS(ns, 'path');
          arc.setAttribute('d', `M${x1},${y1} Q${mx},${my} ${x2},${y2}`);
          arc.setAttribute('fill', 'none');
          arc.setAttribute('stroke', r.color);
          arc.setAttribute('stroke-width', '2.5');
          arc.setAttribute('opacity', '0.45');
          arc.setAttribute('stroke-dasharray', '10 7');
          const ad = document.createElementNS(ns, 'animate');
          ad.setAttribute('attributeName', 'stroke-dashoffset');
          ad.setAttribute('values', '0;-34');
          ad.setAttribute('dur', `${1.5+i*0.3}s`);
          ad.setAttribute('repeatCount', 'indefinite');
          arc.appendChild(ad);
          overlay.appendChild(arc);
          const dot = document.createElementNS(ns, 'circle');
          dot.setAttribute('r', '5');
          dot.setAttribute('fill', r.color);
          const am = document.createElementNS(ns, 'animateMotion');
          am.setAttribute('dur', `${3+i*0.4}s`);
          am.setAttribute('repeatCount', 'indefinite');
          am.setAttribute('path', `M${x1},${y1} Q${mx},${my} ${x2},${y2}`);
          dot.appendChild(am);
          overlay.appendChild(dot);
          [{ cx: x1, cy: y1 }, { cx: x2, cy: y2 }].forEach(pt => {
            const city = document.createElementNS(ns, 'circle');
            city.setAttribute('cx', pt.cx); city.setAttribute('cy', pt.cy);
            city.setAttribute('r', '5'); city.setAttribute('fill', r.color); city.setAttribute('opacity', '0.7');
            const p = document.createElementNS(ns, 'animate');
            p.setAttribute('attributeName', 'r'); p.setAttribute('values', '4;9;4');
            p.setAttribute('dur', '2.5s'); p.setAttribute('repeatCount', 'indefinite');
            city.appendChild(p);
            overlay.appendChild(city);
          });
        });
        svg.appendChild(overlay);
      });
  }, []);

  useEffect(() => {
    const handleScroll = () => setScrollY(window.scrollY);
    window.addEventListener('scroll', handleScroll, { passive: true });
    return () => window.removeEventListener('scroll', handleScroll);
  }, []);

  return (
    <div className="landing">
      {/* Nav */}
      <nav className={`landing-nav ${scrollY > 50 ? 'scrolled' : ''}`}>
        <div className="landing-nav-inner">
          <div className="landing-logo">
            <FaMountain className="landing-logo-icon" />
            <span>MyTravelGlimpse</span>
          </div>
          <div className="landing-nav-links">
            <a href="#features" className="nav-link-text">Features</a>
            <a href="#how" className="nav-link-text">How It Works</a>
          </div>
          <div className="landing-nav-actions">
            <button className="nav-btn-ghost" onClick={() => navigate('/login')}>Log In</button>
            <button className="nav-btn-primary" onClick={() => navigate('/signup')}>
              Start Free <FaArrowRight />
            </button>
          </div>
        </div>
      </nav>

      {/* Hero */}
      <section className="landing-hero">
        <div className="hero-bg-shapes">
          <div className="hero-shape hero-shape-1" />
          <div className="hero-shape hero-shape-2" />
          <div className="hero-shape hero-shape-3" />
        </div>
        <div className="hero-content">
          <div className="hero-badge">
            <FaPlane className="hero-badge-icon" /> Your Personal Travel Map
          </div>
          <h1 className="hero-title">
            Every Journey<br />
            <span className="hero-gradient-text">Deserves a Glimpse</span>
          </h1>
          <p className="hero-subtitle">
            Pin visited states on India's map. Track countries across the world.
            Journal every destination. Watch your travel story come alive.
          </p>
          <div className="hero-actions">
            <button className="hero-btn-primary" onClick={() => navigate('/signup')}>
              <FaSuitcaseRolling /> Start Your Map
            </button>
            <button className="hero-btn-secondary" onClick={() => navigate('/login')}>
              <FaPassport /> I Have an Account
            </button>
          </div>
          {/* Mini stats */}
          <div className="hero-mini-stats">
            <div className="hms"><strong>36</strong> States & UTs</div>
            <div className="hms-dot" />
            <div className="hms"><strong>195+</strong> Countries</div>
            <div className="hms-dot" />
            <div className="hms"><strong>1000+</strong> Destinations</div>
          </div>
        </div>
        <div className="hero-visual">
          <div className="hero-map-real">
            <div className="hero-map-container" ref={mapRef} />
          </div>
          {/* Decorative travel icons floating */}
          <div className="hero-float-icon fi-1"><FaPlane /></div>
          <div className="hero-float-icon fi-2"><FaCamera /></div>
          <div className="hero-float-icon fi-3"><FaMapPin /></div>
        </div>
      </section>

      {/* Marquee */}
      <section className="travel-marquee">
        <div className="marquee-track">
          {['Goa', 'Paris', 'Tokyo', 'Kerala', 'Sydney', 'New York', 'Jaipur', 'London', 'Bali', 'Dubai', 'Manali', 'Rome', 'Ladakh', 'Bangkok', 'Maldives', 'Goa', 'Paris', 'Tokyo', 'Kerala', 'Sydney', 'New York', 'Jaipur', 'London', 'Bali', 'Dubai', 'Manali', 'Rome', 'Ladakh', 'Bangkok', 'Maldives'].map((city, i) => (
            <span key={i} className="marquee-item">
              <FaMapPin className="marquee-pin" /> {city}
            </span>
          ))}
        </div>
      </section>

      {/* Features */}
      <section className="landing-features" id="features">
        <div className="features-header">
          <div className="section-badge"><FaRoute /> Features</div>
          <h2>Built for Travelers<br />Who Love to <span className="hero-gradient-text">Explore</span></h2>
          <p>Every feature designed around the joy of discovery</p>
        </div>
        <div className="features-grid">
          {features.map((f, i) => (
            <div key={i} className="feature-card" style={{ animationDelay: `${i * 0.08}s` }}>
              <div className="feature-icon">{f.icon}</div>
              <h3>{f.title}</h3>
              <p>{f.desc}</p>
            </div>
          ))}
        </div>
      </section>

      {/* How It Works */}
      <section className="landing-how" id="how">
        <div className="how-header">
          <div className="section-badge"><FaSuitcaseRolling /> How It Works</div>
          <h2>Start in <span className="hero-gradient-text">60 Seconds</span></h2>
        </div>
        <div className="how-steps">
          <div className="how-step">
            <div className="how-step-num">1</div>
            <h3>Create Free Account</h3>
            <p>Sign up in seconds. No credit card required.</p>
          </div>
          <div className="how-connector"><FaPlane className="connector-icon" /></div>
          <div className="how-step">
            <div className="how-step-num">2</div>
            <h3>Pin Your Travels</h3>
            <p>Click on maps to mark states and countries you have visited.</p>
          </div>
          <div className="how-connector"><FaPlane className="connector-icon" /></div>
          <div className="how-step">
            <div className="how-step-num">3</div>
            <h3>Watch Your Story</h3>
            <p>See analytics, unlock badges, and relive your adventures.</p>
          </div>
        </div>
      </section>

      {/* Testimonials */}
      <section className="landing-testimonials">
        <div className="testimonials-header">
          <div className="section-badge"><FaCamera /> Travelers Love Us</div>
          <h2>What Explorers <span className="hero-gradient-text">Say</span></h2>
        </div>
        <div className="testimonials-grid">
          {testimonials.map((t, i) => (
            <div key={i} className="testimonial-card" style={{ animationDelay: `${i * 0.1}s` }}>
              <p className="testimonial-text">"{t.text}"</p>
              <div className="testimonial-author">
                <div className="testimonial-avatar">{t.name[0]}</div>
                <div>
                  <div className="testimonial-name">{t.name}</div>
                  <div className="testimonial-role">{t.role}</div>
                </div>
              </div>
            </div>
          ))}
        </div>
      </section>

      {/* CTA */}
      <section className="landing-cta">
        <div className="cta-content">
          <FaMountain className="cta-icon" />
          <h2>Your Next Adventure Starts Here</h2>
          <p>Join MyTravelGlimpse and turn every trip into a story worth tracking</p>
          <button className="hero-btn-primary cta-btn" onClick={() => navigate('/signup')}>
            Create Free Account <FaArrowRight />
          </button>
        </div>
      </section>

      {/* Footer */}
      <footer className="landing-footer">
        <div className="footer-inner">
          <div className="landing-logo">
            <FaMountain className="landing-logo-icon" />
            <span>MyTravelGlimpse</span>
          </div>
          <div className="footer-links">
            <a href="#features">Features</a>
            <a href="#how">How It Works</a>
            <span onClick={() => navigate('/login')}>Log In</span>
          </div>
          <p>&copy; {new Date().getFullYear()} MyTravelGlimpse. Built for travelers.</p>
        </div>
      </footer>
    </div>
  );
}
